import{_ as e,o as i,c as a,a2 as n}from"./chunks/framework.BWuWLRhz.js";const k=JSON.parse('{"title":"Cross-plugin references and dependency discovery","description":"","frontmatter":{"rfc":41,"title":"Cross-plugin references and dependency discovery","status":"Draft","date":"June 2026","author":"kasunben","scope":"packages/sdk, runtime, packages/db, packages/manifest, plugins/account, plugins/console, docs; builds on RFC 0002 and RFC 0047","incorporated_into_plan":"Yes — epic task 3.20"},"headers":[],"relativePath":"rfcs/0051-cross-plugin-references.md","filePath":"rfcs/0051-cross-plugin-references.md"}'),t={name:"rfcs/0051-cross-plugin-references.md"};function l(r,s,o,h,p,d){return i(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="rfc-0051-—-cross-plugin-references-and-dependency-discovery" tabindex="-1">RFC 0051 — Cross-plugin References and Dependency Discovery <a class="header-anchor" href="#rfc-0051-—-cross-plugin-references-and-dependency-discovery" aria-label="Permalink to &quot;RFC 0051 — Cross-plugin References and Dependency Discovery&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Define a platform convention for optional plugin dependencies and opaque cross-plugin references. Plugins can discover whether another plugin is installed, enabled, available to the current user, and consented for a contract. Plugins can also store references to provider-owned records without importing provider schemas or copying private data.</p><p>This complements RFC 0002 data contracts and RFC 0047 tool contracts. Those RFCs define how to read data and perform actions. This RFC defines how consumers represent links, handle stale references, and build good degraded UI.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Composable plugins need to point at each other&#39;s records:</p><ul><li>a conversation linked to a contact;</li><li>an invoice linked to a customer and originating conversation;</li><li>a health note linked to a file or message;</li><li>an assistant action referencing records across multiple providers.</li></ul><p>Direct foreign keys across plugin tables break plugin isolation. Raw strings work technically, but without a convention every plugin will handle stale links, cached labels, consent revocation, and provider uninstall differently.</p><h2 id="current-state" tabindex="-1">Current state <a class="header-anchor" href="#current-state" aria-label="Permalink to &quot;Current state&quot;">​</a></h2><ul><li>RFC 0002 specifies consented read-only data contracts.</li><li>RFC 0047 specifies provider-owned tool execution.</li><li>Middleware injects current plugin ID for data queries.</li><li>There is no <code>sdk.plugins</code> discovery API or standard cross-plugin reference shape.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="dependency-discovery" tabindex="-1">Dependency discovery <a class="header-anchor" href="#dependency-discovery" aria-label="Permalink to &quot;Dependency discovery&quot;">​</a></h3><p>Add <code>sdk.plugins</code>:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.plugins.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(id: string): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PluginAvailability</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.plugins.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">list</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(filter</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { providesContract?: string }): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PluginAvailability[]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sdk.plugins.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">getConsentStatus</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ref: DataContractRef): </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Promise</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ConsentStatus</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><code>PluginAvailability</code> includes:</p><ul><li>plugin ID, name, route prefix, and icon metadata;</li><li>installed/enabled/disabled status;</li><li>whether the current user can launch it;</li><li>whether requested data/tool contracts are declared;</li><li>whether a matching consent grant exists.</li></ul><p>The API does not expose private provider data.</p><h3 id="reference-shape" tabindex="-1">Reference shape <a class="header-anchor" href="#reference-shape" aria-label="Permalink to &quot;Reference shape&quot;">​</a></h3><p>Define a standard reference object for plugin-owned records:</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">interface</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> PluginReference</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  providerId</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  resourceType</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  resourceId</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  contract</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  version</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> number</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  labelSnapshot</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  metadata</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> unknown</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">  linkedAt</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Plugins may store this object in their own tables, or split it into columns. <code>resourceId</code> is opaque to the consumer. The provider decides whether it is a UUID, slug, compound key, or stable public ID.</p><h3 id="stale-and-revoked-references" tabindex="-1">Stale and revoked references <a class="header-anchor" href="#stale-and-revoked-references" aria-label="Permalink to &quot;Stale and revoked references&quot;">​</a></h3><p>Consumers must treat references as nullable links:</p><ul><li>provider unavailable: show snapshot and disabled link;</li><li>consent revoked: show &quot;access revoked&quot; state and offer re-consent;</li><li>resource deleted: show &quot;deleted or unavailable&quot; state;</li><li>provider version mismatch: show degraded state and avoid destructive actions.</li></ul><p>Providers should expose lightweight lookup contracts where appropriate so consumers can refresh labels or check existence without reading full records.</p><h3 id="manifest-declarations" tabindex="-1">Manifest declarations <a class="header-anchor" href="#manifest-declarations" aria-label="Permalink to &quot;Manifest declarations&quot;">​</a></h3><p>Optional manifest metadata can improve install/discovery UX:</p><div class="language-jsonc vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">jsonc</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;integrations&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;optional&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;provider&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;io.openfs.sovereign.crm&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;reason&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Link records to contacts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;contracts&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;crm.contacts.lookup&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">        &quot;tools&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;crm.timeline.addEntry&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Optional integrations are not install blockers. They power Console, Account, Launcher, and plugin UI hints.</p><h2 id="security-requirements" tabindex="-1">Security requirements <a class="header-anchor" href="#security-requirements" aria-label="Permalink to &quot;Security requirements&quot;">​</a></h2><ul><li>References are not authorization. Every dereference still uses data/tool contracts and current user consent.</li><li>Consumers cannot infer private provider records from discovery alone.</li><li>Cached snapshots are minimal and may be stale.</li><li>Provider uninstall or disable never breaks consumer table integrity.</li><li>Cross-plugin references are exported as inert metadata unless the user also exports the provider data.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><h3 id="direct-foreign-keys-across-plugin-tables" tabindex="-1">Direct foreign keys across plugin tables <a class="header-anchor" href="#direct-foreign-keys-across-plugin-tables" aria-label="Permalink to &quot;Direct foreign keys across plugin tables&quot;">​</a></h3><p>Rejected. It couples schemas and makes plugin uninstall/migration brittle.</p><h3 id="require-all-integrations-to-be-hard-dependencies" tabindex="-1">Require all integrations to be hard dependencies <a class="header-anchor" href="#require-all-integrations-to-be-hard-dependencies" aria-label="Permalink to &quot;Require all integrations to be hard dependencies&quot;">​</a></h3><p>Rejected. Many plugin families should degrade gracefully when a sibling plugin is missing or disabled.</p><h3 id="let-each-plugin-invent-its-own-reference-shape" tabindex="-1">Let each plugin invent its own reference shape <a class="header-anchor" href="#let-each-plugin-invent-its-own-reference-shape" aria-label="Permalink to &quot;Let each plugin invent its own reference shape&quot;">​</a></h3><p>Rejected. It leads to inconsistent UI, export, deletion, and consent behavior.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li>Should <code>resourceType</code> names be provider-local strings or registered contract resource kinds?</li><li>Should the platform provide a generic link resolver UI primitive?</li><li>Should optional integrations appear in the plugin manifest validation output?</li><li>Should references carry a stable provider instance ID for future multi-instance plugin support?</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li>Add reference-shape docs and TypeScript types to the SDK.</li><li>Add <code>sdk.plugins</code> discovery and consent-status helpers.</li><li>Add optional integration manifest metadata.</li><li>Add Account/Console UI for visible app connections.</li><li>Update plugin development docs with stale-link and export patterns.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>June 2026</td><td>Initial draft</td></tr></tbody></table>`,44)])])}const u=e(t,[["render",l]]);export{k as __pageData,u as default};
